INSERT OR REPLACE INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment) VALUES ('Alex_C.T - 4K Plex Series', 'Manual 4K Sonarr profile for shows that deserve the 2160p path. Profilarr ladder displays top-to-bottom as Bluray-2160p then WEBDL-2160p, with curated scoring for efficient HDR/Dolby Vision encodes, strong EN+ES/MULTI language handling, 5.1+ audio, and clean 4K sources. SDR 4K, 4K x264, weak 4K rips, AAC-only style 4K, Remux, and 4K without 5.1+ surround are blocked or heavily penalized. Target rip quality: 10/10.', 1, 1100, 16000, 125);
